if (! function_exists('text_table_formatter')) {
    function text_table_formatter($headers, $rows, $title = null, $borders = null, $align = null)
    {
        $headers = $headers;
        $rows = $rows;
        $title = $title ?? '';
        $borders = $borders ?? false;
        $align = $align ?? 'left';

        // Determine number of columns
        $numCols = count($headers);
        foreach ($rows as $row) {
            $numCols = max($numCols, count($row));
        }

        // Pad rows to match column count
        $paddedRows = [];
        foreach ($rows as $row) {
            $r = $row;
            while (count($r) < $numCols) $r[] = '';
            $paddedRows[] = $r;
        }

        // Calculate column widths
        $colWidths = [];
        for ($i = 0; $i < $numCols; $i++) {
            $w = mb_strlen((string)($headers[$i] ?? ''));
            foreach ($paddedRows as $row) {
                $w = max($w, mb_strlen((string)($row[$i] ?? '')));
            }
            $colWidths[] = $w;
        }

        // Alignment per column
        $alignments = [];
        if (is_array($align)) {
            $alignments = $align;
        } else {
            for ($i = 0; $i < $numCols; $i++) {
                $alignments[] = $align;
            }
        }

        // Pad cell to width with alignment
        $padCell = function($val, $width, $align) {
            $val = (string)$val;
            $len = mb_strlen($val);
            if ($len >= $width) return $val;
            $pad = $width - $len;
            if ($align === 'right') return str_repeat(' ', $pad) . $val;
            if ($align === 'center') {
                $left = (int)($pad / 2);
                $right = $pad - $left;
                return str_repeat(' ', $left) . $val . str_repeat(' ', $right);
            }
            // left
            return $val . str_repeat(' ', $pad);
        };

        $renderRow = function($cells) use ($colWidths, $alignments, $padCell, $numCols) {
            $parts = [];
            for ($i = 0; $i < $numCols; $i++) {
                $parts[] = $padCell($cells[$i] ?? '', $colWidths[$i], $alignments[$i] ?? 'left');
            }
            return $parts;
        };

        $output = '';

        // Title
        if ($title !== '') {
            $totalWidth = array_sum($colWidths) + ($numCols - 1) * 3;
            if ($borders) $totalWidth += 4;
            $output .= $title . "\n" . str_repeat('=', $totalWidth) . "\n";
        }

        if ($borders) {
            // Top border
            $parts = [];
            foreach ($colWidths as $w) {
                $parts[] = str_repeat('═', $w + 2);
            }
            $output .= '╔' . implode('╤', $parts) . "╗\n";

            // Header row
            $headerParts = $renderRow($headers);
            $output .= '║ ' . implode(' │ ', $headerParts) . " ║\n";

            // Separator
            $parts = [];
            foreach ($colWidths as $w) {
                $parts[] = str_repeat('─', $w + 2);
            }
            $output .= '╟' . implode('┼', $parts) . "╢\n";

            // Data rows
            foreach ($paddedRows as $row) {
                $dataParts = $renderRow($row);
                $output .= '║ ' . implode(' │ ', $dataParts) . " ║\n";
            }

            // Bottom border
            $parts = [];
            foreach ($colWidths as $w) {
                $parts[] = str_repeat('═', $w + 2);
            }
            $output .= '╚' . implode('╧', $parts) . "╗\n";
        } else {
            // Simple aligned format
            $headerParts = $renderRow($headers);
            $output .= implode('   ', $headerParts) . "\n";
            $output .= implode('   ', array_map(function($w) { return str_repeat('─', $w); }, $colWidths)) . "\n";
            foreach ($paddedRows as $row) {
                $dataParts = $renderRow($row);
                $output .= implode('   ', $dataParts) . "\n";
            }
        }

        return json_encode([
            'rendered' => $output,
            'columns' => $numCols,
            'rows' => count($paddedRows),
            'col_widths' => $colWidths,
            'borders' => $borders,
        ]);
    }
